const GEMINI_CONFIG = {
  // スクリプトプロパティ 'GEMINI_API_KEY'
  API_KEY: PropertiesService.getScriptProperties().getProperty('GEMINI_API_KEY'),
  MODEL_NAME: 'gemini-2.5-flash',
};

/**
 * デバッグログをスプレッドシートに記録する
 * @param {string} msg 記録するメッセージ
 */
function logToSheet_(msg) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    let sh = ss.getSheetByName('DEBUG_LOG');
    if (!sh) sh = ss.insertSheet('DEBUG_LOG');
    sh.appendRow([new Date(), String(msg)]);
  } catch (e) { }
}

/**
 * AIシステムが利用可能かチェックする
 * @returns {boolean} AIシステムが利用可能であればtrue
 */
function isAiSystemReady_() {
  if (!GEMINI_CONFIG.API_KEY) {
    logToSheet_('【システム通知】GEMINI_API_KEY がスクリプトプロパティに設定されていません。スプレッドシートの「設定」などを確認してください。');
    return false;
  }
  return true;
}

/**
 * Gemini（Vertex AI 互換）を通じてランキング分析を実行
 * @param {Array} contextData 現在の計算式で出された上位曲リスト
 * @param {string} typeLabel 'Daily' or 'Weekly'
 */
function analyzeRankingWithAi(contextData, typeLabel) {
  if (!isAiSystemReady_()) {
    logToSheet_('AI System is not ready or keys are missing. Skipping analysis.');
    return null;
  }

  try {
    const totalSongs = contextData.length;
    const chunkSize = 3; // 1回あたり3曲ずつ解析 (30曲を10回で処理) に縮小して安定化
    const allResultsMap = new Map();

    SpreadsheetApp.getActiveSpreadsheet().toast(`AI分析を開始します (全${totalSongs}曲 / ${chunkSize}曲ずつ分割実行)...`, 'Gemini AI', 5);
    logToSheet_(`Starting Chunked Gemini Analysis for ${typeLabel} (Total: ${totalSongs}, Chunk: ${chunkSize})`);

    for (let i = 0; i < totalSongs; i += chunkSize) {
      const chunkData = contextData.slice(i, i + chunkSize);
      const simplifiedData = chunkData.map(c => ({
        id: c.id,
        artist: c.artist,
        title: c.title,
        rank_change: c.rankChange || 'NEW',
        prev_rank: c.prevRank || 100,
        daily_views: c.dv,
        total_views: c.totalV,
        total_engagement: c.totalL + c.totalC,
        growth_rate: (c.growth * 100).toFixed(1) + '%',
        engagement: (c.eng * 100).toFixed(2) + '%',
        is_long_term: c.isLongTerm || false,
        days_since_launch: c.publishedAt ? Math.floor((new Date() - new Date(c.publishedAt)) / (1000 * 60 * 60 * 24)) : '-',
        tags: (c.tags || []).slice(0, 10).join(','),
        description: (c.description || '').slice(0, 300),
        comments_sample: fetchComments_(c.id).text
      }));

      const isWeekly = (typeLabel === 'Weekly');
      const prompt = `
# Role
Expert Music Industry Analyst and Digital Trend Researcher specializing in the Cambodian music market. 
You provide sophisticated, data-backed commentary for elite music rankings.

# Task
Analyze the following ${simplifiedData.length} songs. Your goal is to explain the "Reasoning for the Rank" using the provided data.
Ranking Type: ${typeLabel}

# Data
${JSON.stringify(simplifiedData)}

# Directives for 'insight' (English, 2-3 sentences):
- **Data-Backed Reasoning**: Explain the rank using specific ratios. (e.g., "Maintains #1 due to consistent 1M+ total views and an exceptional 5% engagement rate which suggests a loyal fan base.")
- **Trend Analysis**: Reference 'rank_change' and 'prev_rank'. (e.g., "Climbing 5 spots this week as growth momentum surged to 20%.")
- **Sentiment Alignment**: Use 'comments_sample' to corroborate the numbers. (e.g., "The high engagement is backed by an outpouring of appreciation for the lyrics in the comments.")
- **Comment Quality Audit**: Evaluate 'comments_sample' for "Meaningful Content" vs "Generic/Spam". 
  - Meaningful: Specific mention of melody, lyrics, artist's voice, or personal feelings.
  - Generic/Spam: Just emojis, "Nice", bot-like repetition.
- **Avoid Generic Praise**: Do NOT use phrases like "This is a great song" or "Strong debut". Focus on the "Why" of the rank.
- **ID Preservation**: DO NOT ALTER THE id. Return it exactly as provided.
- **Scoring Consistency**: Use the following internal weights for aiHeatScore:
  - 40%: Daily View Count (Volume)
  - 30%: Engagement Rate (Likes/Comments ratio)
  - 20%: Growth Momentum (Daily increase relative to total)
  - 10%: Cumulative Stature (Total views/History)
- **Deterministic**: Always provide the same score for the same input data.

# Requirements for each song:
1. ID Preservation: **DO NOT ALTER THE id**. Return it exactly as it was provided.
2. Naming Normalization: Show clean artist and title (Remove "Official", "Production", "MV" suffixes).
3. aiHeatScore (0-200): Calculate based on VIEW VOLUME + GROWTH MOMENTUM + ENGAGEMENT QUALITY. Over-weighting just one is a mistake.
4. aiReason (Japanese): Concise data-focused logic (60-80 chars). e.g., "再生数とエンゲージメント率のバランスがトップ。TikTokでのバズがコメント欄から確認できる。"
5. insight (English): A 2-3 sentence journalistic analysis.
   - DO NOT repeat phrases like "This track marks a strong debut". Be creative.
   - Cross-reference view growth with engagement.
   - **CRITICAL**: Use 'comments_sample' to mention WHY fans are listening.
6. shortInsight (English): A punchy summary (max 10 words).
7. commentQualityScore (0.0 to 1.0): **CRITICAL**. Analyze 'comments_sample'.
   - 0.8-1.0: Deep, specific, and passionate fans.
   - 0.5-0.7: Mixed content or generic appreciation.
   - 0.0-0.4: Dominated by spam, emojis, or one-word repetitive comments.
8. genre & visualConcept: Be analytical.

# Format (JSON Array only)
- Return a JSON array of objects.
- Ensure the 'id' field matches the input exactly.
[{ "id": "...", "artist": "...", "title": "...", "aiHeatScore": 150, "aiReason": "...", "insight": "...", "shortInsight": "...", "commentQualityScore": 0.9, "genre": "...", "visualConcept": "..." }]
`;

      logToSheet_(`Batch ${Math.floor(i / chunkSize) + 1} call...`);
      const response = callGeminiApi_(prompt);
      if (!response) {
        logToSheet_(`Batch ${Math.floor(i / chunkSize) + 1} returned null. Skipping.`);
        continue;
      }

      // JSON抽出 (より堅牢な方法)
      let jsonStr = response.trim();
      const jsonMatch = jsonStr.match(/\[[\s\S]*\]/); // 配列 [...] を探す
      if (jsonMatch) {
          jsonStr = jsonMatch[0];
      } else {
          // バックアップ: 既存のコードブロック除去
          if (jsonStr.startsWith('```json')) jsonStr = jsonStr.substring(7);
          else if (jsonStr.startsWith('```')) jsonStr = jsonStr.substring(3);
          if (jsonStr.endsWith('```')) jsonStr = jsonStr.substring(0, jsonStr.length - 3);
          jsonStr = jsonStr.trim();
      }

      try {
        const result = JSON.parse(jsonStr);
        const results = Array.isArray(result) ? result : (result.results || []);
        results.forEach(item => {
          if (item.id) allResultsMap.set(String(item.id), item);
          else allResultsMap.set(`${item.artist} - ${item.title}`, item);
        });
        logToSheet_(`Batch ${Math.floor(i / chunkSize) + 1} success: ${results.length} songs analyzed.`);
      } catch (parseError) {
        logToSheet_(`Batch ${Math.floor(i / chunkSize) + 1} JSON Parse Error: ${parseError.message}. Snippet: ${jsonStr.slice(0, 100)}...`);
        // エラーの詳細をログ出力 (デバッグ用)
        console.error(`Batch ${Math.floor(i / chunkSize) + 1} Raw Response:`, response);
      }
    }

    logToSheet_(`Total results collected: ${allResultsMap.size}`);
    return allResultsMap.size > 0 ? allResultsMap : null;

  } catch (e) {
    logToSheet_('Gemini Chunked Analysis Error: ' + e.message + '\n' + e.stack);
    return null;
  }
}

/**
 * 指定した動画のコメントを最新順に取得し、質の低い（無意味な）コメントを除外・判定する
 * @param {string} videoId 
 * @returns {object} { text: string, cleanRatio: number }
 */
function fetchComments_(videoId) {
  let rawComments = [];

  try {
    const options = {
      videoId: videoId,
      maxResults: 50,
      order: 'relevance'
    };

    const res = YouTube.CommentThreads.list('snippet', options);
    updateApiUsage_('YouTube', 1); // 1 unit
    
    if (res && res.items) {
      res.items.forEach(it => {
        rawComments.push(it.snippet.topLevelComment.snippet.textDisplay);
      });
    }

    if (rawComments.length === 0) return { text: "", cleanRatio: 1.0 };

    // --- 機械的フィルタリング (Regex) ---
    const meaningfulComments = rawComments.filter(text => {
      const clean = text.replace(/<[^>]*>/g, "").trim(); // HTMLタグ除去
      if (clean.length < 3) return false; // 短すぎる
      if (/^[\W_]+$/.test(clean.replace(/\s/g, ""))) return false; // 記号・絵文字のみ
      if (/(.)\1{4,}/.test(clean)) return false; // 同じ文字の5回以上の繰り返し
      return true;
    });

    const cleanRatio = meaningfulComments.length / rawComments.length;
    return {
      text: meaningfulComments.join("\n").slice(0, 5000),
      cleanRatio: Math.max(0.1, cleanRatio)
    };
  } catch (e) {
    Logger.log(`Comment Fetch Error [${videoId}]: ${e.message}`);
    return { text: "", cleanRatio: 1.0 };
  }
}

/**
 * Gemini API 呼び出し用の内部関数 (Vertex AI API 互換)
 */
function callGeminiApi_(prompt) {
  const url = `https://generativelanguage.googleapis.com/v1/models/${GEMINI_CONFIG.MODEL_NAME}:generateContent?key=${GEMINI_CONFIG.API_KEY}`;
  const maxRetries = 5;
  let retryCount = 0;
  let backoffMs = 15000;

  const payload = {
    contents: [{
      parts: [{ text: prompt }]
    }],
    generationConfig: {
      temperature: 0.0,
      topP: 0.95,
      topK: 40,
      maxOutputTokens: 16384
    },
    safetySettings: [
      { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_NONE" },
    ]
  };

  const options = {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  while (retryCount < maxRetries) {
    const response = UrlFetchApp.fetch(url, options);
    const resCode = response.getResponseCode();
    const resText = response.getContentText();

    if (resCode === 200) {
      if (!resText) {
        logToSheet_("Gemini API Error: Empty response text");
        return null;
      }
      const resJson = JSON.parse(resText);
      if (!resJson.candidates || !resJson.candidates[0].content || !resJson.candidates[0].content.parts) {
        logToSheet_("Gemini API Error: Unexpected response structure : " + resText);
        return null;
      }
      
      // トークン使用量の記録
      if (resJson.usageMetadata && resJson.usageMetadata.totalTokenCount) {
        updateApiUsage_('Gemini', resJson.usageMetadata.totalTokenCount);
      } else {
        updateApiUsage_('Gemini', 0); // Count request even if tokens missing
      }
      
      return resJson.candidates[0].content.parts[0].text;
    }

    if (resCode === 429 || resCode === 500 || resCode === 503 || resCode === 504) {
      const msg = `API混雑または一時的なエラー (Code: ${resCode}, Retry ${retryCount + 1}/${maxRetries}): ${backoffMs / 1000}秒待機します...`;
      SpreadsheetApp.getActiveSpreadsheet().toast(msg, 'Gemini AI', 10);
      logToSheet_(`Gemini API ${resCode} (Retry ${retryCount + 1}/${maxRetries}): Waiting ${backoffMs}ms... Error: ${resText.slice(0, 200)}`);
      Utilities.sleep(backoffMs);
      retryCount++;
      backoffMs *= 2;
      if (backoffMs > 60000) backoffMs = 60000; // Cap backoff at 60s
      continue;
    }

    logToSheet_(`Gemini API Error (${resCode}) at ${url.split('?')[0]}: ${resText}`);
    return null; // Non-retryable error
  }

  logToSheet_("Gemini API Error: Max retries reached for 429.");
  return null;
}

/**
 * AI設定の状態を確認し、ログに出力する。
 */
function checkAiConfiguration() {
  const key = PropertiesService.getScriptProperties().getProperty('GEMINI_API_KEY');
  if (!key) {
    Logger.log('❌ GEMINI_API_KEY が設定されていません。Project Settings > Script Properties に追加してください。');
  } else {
    Logger.log('✅ GEMINI_API_KEY は設定されています (末尾: ...' + key.slice(-4) + ')');
    testListModels(); // 通信テスト
  }
}

/**
 * 利用可能なモデル一覧をログに出力し、APIキーの有効性をテスト。
 */
function testListModels() {
  // モデル一覧取得は v1beta のみサポート
  const url = `https://generativelanguage.googleapis.com/v1/models?key=${GEMINI_CONFIG.API_KEY}`;
  try {
    const response = UrlFetchApp.fetch(url, { muteHttpExceptions: true });
    const code = response.getResponseCode();
    const content = response.getContentText();
    if (code === 200) {
      const json = JSON.parse(content);
      const names = json.models.map(m => m.name.replace('models/', ''));
      Logger.log('【診断】利用可能なモデル一覧: ' + names.join(', '));
      Logger.log('【アドバイス】もし gemini-1.5-flash が無い場合は、上記リストにあるモデル名を PickSongs.gs の GEMINI_CONFIG.MODEL_NAME に設定してください。');
    } else {
      Logger.log(`❌ モデル一覧の取得に失敗 (Code: ${code}): ${content}`);
    }
  } catch (e) {
    Logger.log(`❌ 通信エラー: ${e.message}`);
  }
}

