function debugTop5HeatScore() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const shSnap = ss.getSheetByName(CFG.SHEET_SNAPSHOT);
  const snap = shSnap.getDataRange().getValues();
  if (snap.length < 2) return;

  const tz = Session.getScriptTimeZone();
  const toDateKey = (v) => toDateKey_(v, tz);

  const dateSet = new Set();
  for (let i = 1; i < snap.length; i++) {
    const dk = toDateKey(snap[i][0]);
    if (dk) dateSet.add(dk);
  }
  const dates = Array.from(dateSet).sort();
  if (dates.length < 2) return;
  const latestDate = dates[dates.length - 1];

  let baseDate = dates[dates.length - 2]; // For daily

  const LMap = new Map();
  const BMap = new Map();

  for (let i = 1; i < snap.length; i++) {
    const dt = toDateKey(snap[i][0]);
    const id = String(snap[i][1]).trim();
    const v = Number(snap[i][2]) || 0;
    const l = Number(snap[i][3]) || 0;
    const c = Number(snap[i][4]) || 0;

    if (dt === latestDate) LMap.set(id, { v, l, c });
    if (dt === baseDate) BMap.set(id, { v, l, c });
  }

  let shRank = ss.getSheetByName('TEST_RANKING');
  if (!shRank) {
    shRank = ss.getSheetByName('DailyRanking');
  }
  if (!shRank) {
    logToSheet_("ERROR: Neither TEST_RANKING nor DailyRanking sheet found.");
    return;
  }
  const rankData = shRank.getDataRange().getValues();
  const topIds = [];
  for (let i = 1; i <= 5; i++) {
    if (rankData[i] && rankData[i][22]) {
      topIds.push(rankData[i][22].trim()); // videoId is in col 23 (index 22)
    }
  }

  logToSheet_("=== HEAT SCORE MATH DEGUG ===");
  topIds.forEach((id, idx) => {
    const L = LMap.get(id);
    let B = BMap.get(id);

    // If no baseline from snap, assume 0 for exact fresh track scenario
    if (!B) B = { v: 0, l: 0, c: 0 };

    const dvRaw = L.v - B.v;
    const dlRaw = L.l - B.l;
    const dcRaw = L.c - B.c;

    const dv = Math.max(0, dvRaw);
    const dl = Math.max(0, dlRaw);
    const dc = Math.max(0, dcRaw);

    const scale = 1 + (Math.log10(L.v + 1) / 10);

    const heat_dv = 5 * Math.log(dv + 1) * scale;
    const heat_dl = 3 * Math.log(dl + 1);
    const heat_dc = 5 * Math.log(dc + 1);

    const heat = heat_dv + heat_dl + heat_dc;

    logToSheet_(`Rank ${idx + 1}: [${id}]`);
    logToSheet_(`- L.v/l/c = ${L.v}/${L.l}/${L.c} | B.v/l/c = ${B.v}/${B.l}/${B.c}`);
    logToSheet_(`- dv/dl/dc = ${dv}/${dl}/${dc}`);
    logToSheet_(`- scale(log(L.v+1)) = ${scale.toFixed(4)}`);
    logToSheet_(`- heat_dv = ${heat_dv.toFixed(4)} | heat_dl = ${heat_dl.toFixed(4)} | heat_dc = ${heat_dc.toFixed(4)}`);
    logToSheet_(`- Total Heat = ${heat.toFixed(4)}`);
  });
}

/**
 * 動画のコメントを最大100件取得してテキストとして返す
 * @param {string} videoId 
 * @returns {string} 各コメントを改行で繋いだテキスト
 */
function fetchComments_(videoId) {
  let comments = [];
  let nextPageToken = null;

  try {
    // 1ページ最大50件 × 1回 = 50件取得 (実行時間短縮のため100件から50件に制限)
    for (let i = 0; i < 1; i++) {
      const options = {
        videoId: videoId,
        maxResults: 50,
        order: 'relevance'
      };
      if (nextPageToken) options.pageToken = nextPageToken;

      const res = YouTube.CommentThreads.list('snippet', options);
      updateApiUsage_('YouTube', 1); // 1 unit
      if (!res || !res.items || res.items.length === 0) break;

      res.items.forEach(it => {
        comments.push(it.snippet.topLevelComment.snippet.textDisplay);
      });

      nextPageToken = res.nextPageToken;
      if (!nextPageToken) break;
    }

    if (comments.length === 0) return "";

    // AIへの送信データを5000文字程度に拡大し、より多くのサンプルで判定を安定させる
    return comments
      .join("\n")
      .slice(0, 5000);
  } catch (e) {
    Logger.log(`Comment Fetch Error [${videoId}]: ${e.message}`);
    return "";
  }
}

/**
 * バックグラウンドでAIインサイトを段階的に生成し、シートを更新する非同期パイプライン
 */
function enrichAiInsights_() {
  logToSheet_('SYSTEM: enrichAiInsights_ を開始します');
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const shRank = ss.getSheetByName(CFG.SHEET_RANKING_DAILY);
  if (!shRank) return;

  const data = shRank.getDataRange().getValues();
  if (data.length < 2) return;

  const toProcess = [];
  const chunkSize = 5; // 1回の起動で処理する曲数 (安全圏)

  for (let i = 1; i < data.length; i++) {
    const aiInsight = String(data[i][7]).trim(); // AIScore (H列, Index 7) で判定
    if (aiInsight === '-' || aiInsight === '') {
      toProcess.push({
        rowNum: i + 1,
        id: data[i][25],       // videoId: 26列目 (Index 25)
        rank: data[i][1],      // 順位: 2列目 (Index 1)
        prevRank: data[i][2] === '-' ? 100 : (parseInt(data[i][2]) || 100),
        artist: data[i][3],
        title: data[i][4],
        dv: data[i][17],       // dv: 18列目 (Index 17)
        totalL: data[i][18],   // l: 19列目
        totalC: data[i][19],   // c: 20列目
        totalV: data[i][20],   // totalV: 21列目
        growth: parseFloat(String(data[i][15]).replace('%', '')) || 0, // growth: 16列目
        eng: parseFloat(String(data[i][16]).replace('%', '')) || 0     // eng: 17列目
      });
      if (toProcess.length >= chunkSize) break;
    }
  }

  if (toProcess.length === 0) {
    logToSheet_('enrichAiInsights_: すべての曲のAI分析が完了しています。パイプラインを終了します。');
    // キャッシュを念のため更新
    if (typeof updateRankingCache === 'function') updateRankingCache();
    return;
  }

  logToSheet_(`enrichAiInsights_: ${toProcess.length}件のAI分析を開始します (Rank: ${toProcess.map(x=>x.rank).join(', ')})`);

  // YouTubeメタデータ（タグ、概要欄）の補完
  const topIds = toProcess.map(c => c.id);
  const videoMetaMap = new Map();
  try {
    const videoRes = YouTube.Videos.list('snippet', { id: topIds.join(',') });
    if (videoRes && videoRes.items) {
      videoRes.items.forEach(v => {
        videoMetaMap.set(v.id, {
          description: v.snippet.description,
          tags: v.snippet.tags || []
        });
      });
    }
  } catch (e) {
    logToSheet_('enrichAiInsights_ Video Meta Error: ' + e.message);
  }

  const simplifiedData = toProcess.map(c => {
    const vMeta = videoMetaMap.get(c.id) || {description: '', tags: []};
    const cData = fetchComments_(c.id);
    return {
      id: c.id,
      artist: c.artist,
      title: c.title,
      rank_change: c.prevRank === 100 ? 'NEW' : (c.prevRank - c.rank),
      prev_rank: c.prevRank,
      daily_views: c.dv,
      total_views: c.totalV,
      total_engagement: c.totalL + c.totalC,
      growth_rate: c.growth + '%',
      engagement: c.eng + '%',
      tags: vMeta.tags.slice(0, 10).join(','),
      description: vMeta.description.slice(0, 300),
      comments_sample: cData.text,
      clean_ratio: cData.cleanRatio
    };
  });

  // AI実行 (Chunkingは既に外側で制御しているため、このまま渡す)
  const aiResults = analyzeRankingWithAi(simplifiedData, 'Daily');

  if (aiResults) {
    const aiArray = Array.from(aiResults.values());
    let writeCount = 0;
    
    toProcess.forEach((c, index) => {
      let aiData = aiResults.get(String(c.id)) || aiResults.get(`${c.artist} - ${c.title}`);
      if (!aiData && aiArray.length >= toProcess.length) {
        aiData = aiArray[index];
      }

      if (aiData) {
        // AI結果の構造化
        // Geminiの品質スコアと、機械的なクリーン率を組み合わせる (AI 70% : 機械 30%)
        const geminiQ = Number(aiData.commentQualityScore || aiData.commentqualityscore || 1.0);
        const mechQ = Number(toProcess[index].clean_ratio || 1.0);
        const finalQ = (geminiQ * 0.7) + (mechQ * 0.3);
        
        let qScore = Math.max(0.1, Math.min(1.0, finalQ));

        const ais = [
          aiData.aiHeatScore || aiData.aiScore || Math.floor(c.dv / 1000) || 50, // H (7)
          aiData.aiReason || aiData.aireason || '-',                         // I (8)
          aiData.insight || aiData.aiInsight || aiData.aiinsight || '-',     // J (9)
          aiData.shortInsight || aiData.shortinsight || '-',                 // K (10)
          aiData.genre || aiData.Genre || '-',                               // L (11)
          aiData.visualConcept || aiData.VisualConcept || '-'                // M (12)
        ];

        // H列からM列の6列を一気に書き込み
        shRank.getRange(c.rowNum, 8, 1, 6).setValues([ais]);
        
        // O列 (Index 14 -> 1-based で 15列目) の CommentQuality を更新
        const commq = Math.round(Math.min(1.0, qScore) * 100) + '%';
        shRank.getRange(c.rowNum, 15).setValue(commq);
        
        writeCount++;
      }
    });

    logToSheet_(`enrichAiInsights_: ${writeCount}件の書き込みが成功しました。`);
    
    // まだ未処理の行が残っているかチェックし、あれば1分後に自身を再トリガー
    let remainCount = 0;
    const currentData = shRank.getDataRange().getValues();
    for (let i = 1; i < currentData.length; i++) {
      if (String(currentData[i][7]).trim() === '-') remainCount++;
    }
    
    if (remainCount > 0) {
      logToSheet_(`残りの未処理データが約 ${remainCount} 件あります。1分後に続行します。`);
      ScriptApp.newTrigger('enrichAiInsights_').timeBased().after(60000).create();
    } else {
      logToSheet_('すべてのAIエンリッチメントが完了しました！キャッシュを最終更新します。');
      if (typeof updateRankingCache === 'function') updateRankingCache();
    }
  } else {
    logToSheet_('⚠ enrichAiInsights_: AI処理に失敗しました。5分後にリトライします。');
    ScriptApp.newTrigger('enrichAiInsights_').timeBased().after(300000).create();
  }
}
